class Solution {
public:
    int alternateDigitSum(int n) {
        int sum = 0;
        bool isPositive = true;
        while (n > 0) {
            int digit = n % 10;
            sum += isPositive ? -digit : digit;
            isPositive = !isPositive;
            n /= 10;
        }
        return isPositive ? -sum : sum;
    }
};
```
